const App = () => {
  const names = 'Half Stack application development'
  const part1 = 'Fundamentals of React'
  const exercises1 = 10
  const part2 = 'Using props tco pass data'
  const exercises2 = 7
  const part3 = 'State of a component'
  const exercises3 = 14
  const text = 'Number of exercises '
  const course = {
    nameOfCouse: 'Half Stack application development',
    parts: [
      {
        name: 'Fundamentals of React',
        exercises: 10,
      },
      {
        name: 'Using props to pass data',
        exercises: 7,
      },
      {
        name: 'State of a component',
        exercises: 14,
      },
    ]
  }
  return (
    <div>
      <Header courseName={course.nameOfCouse} />
      <Content parts={course.parts} />
      <Total names={names} part={course.parts} />
      <Total part={course.parts} />
    </div>
  )
}

const Header = (props) => {
  return (
    <h1>{props.courseName}</h1>
  )
}
const Part = props => (
  <p>
    {props.part.name} {props.part.exercises}
  </p>
)

const Content = props => (
  <>
    <Part part={props.parts[0]} />
    <Part part={props.parts[1]} />
    <Part part={props.parts[2]} />
  </>
)
const Total = (props) => {
  return (
    <p>{props.names}{props.names}</p>
  )
}

export default App
